library ieee;
  use ieee.std_logic_1164.all;
  use ieee.math_real.all;
  use work.types_pkg.all;
  use work.config_pkg.all;

entity ORBGRAND_tb is
end entity;

architecture sim of ORBGRAND_tb is
  constant n_max  : integer := 256;
  constant nk_max  : integer := 16;
  constant B      : integer := 6;
  constant B_mag  : integer := 5;
  constant LW_MAX : integer := 104;
  constant HW_MAX : integer := 13;

  signal clk         : std_logic := '0';
  signal rst         : std_logic := '0';
  signal n           : integer range 1 to n_max;
  signal nk           : integer range 1 to nk_max;
  signal dec_en      : std_logic;
  signal H_matrix_id : integer range 0 to NUM_CODES - 1;
  signal LLR_in      : std_logic_vector(n_max * B - 1 downto 0);
  signal y_decoded   : std_logic_vector(n_max - 1 downto 0);
  signal dec_done    : std_logic := '0';

begin
  DUT: entity work.ORBGRAND
    generic map (n_max => n_max, nk_max => nk_max, B => B, B_mag => B_mag, LW_MAX => LW_MAX, HW_MAX => HW_MAX)
    port map (
      clk         => clk,
      rst         => rst,
      n           => n,
      nk           => nk,
      dec_en      => dec_en,
      H_matrix_id => H_matrix_id,
      LLR_in      => LLR_in,
      y_decoded   => y_decoded,
      dec_done    => dec_done
    );

  -- Clock generation
  clk <= not clk after 5 ns;

  -- Stimulus
  process
  begin
    rst <= '1';
    dec_en <= '0';
    LLR_in <= (others => '0');

    wait for 45 ns;

    -- CAPOLAR (n = 128, k = 116)
    rst <= '0';
    n <= 128;
    nk <= 12;
    H_matrix_id <= 0;

    wait until rising_edge(clk);
    dec_en <= '1';

    -- demodulated bits correct decoding no errors
    LLR_in(n * B - 1 downto 0) <= "";
    LLR_in(n_max * B - 1 downto n * B) <= (others => '0');

    wait until rising_edge(clk);
    dec_en <= '0';

    wait for 1000 ns;

    wait until rising_edge(clk);
    dec_en <= '1';

    LLR_in(n * B - 1 downto 0) <= "";
    LLR_in(n_max * B - 1 downto n * B) <= (others => '0');

    wait until rising_edge(clk);
    dec_en <= '0';

    wait for 1000 ns;
    rst <= '1';
    LLR_in <= (others => '0');

    wait for 45 ns;

    -- BCH (n = 127, k = 113)
    rst <= '0';
    n <= 127;
    nk <= 14;
    H_matrix_id <= 1;

    wait until rising_edge(clk);
    dec_en <= '1';

    -- demodulated bits correct decoding no errors
    LLR_in(n * B - 1 downto 0) <= "";
    LLR_in(n_max * B - 1 downto n * B) <= (others => '0');

    wait until rising_edge(clk);
    dec_en <= '0';

    wait for 1000 ns;

    wait until rising_edge(clk);
    dec_en <= '1';

    LLR_in(n * B - 1 downto 0) <= "";
    LLR_in(n_max * B - 1 downto n * B) <= (others => '0');

    wait until rising_edge(clk);
    dec_en <= '0';

    wait;
  end process;
end architecture;

